import{_ as e,o as a,c as t,a2 as n}from"./chunks/framework.B72_uj9U.js";const h=JSON.parse('{"title":"Chapter 17: Packaging and Distribution","description":"Ship your coding agent as a polished binary product, covering release builds, cross-compilation, package managers, auto-updates, and telemetry.","frontmatter":{"title":"Chapter 17: Packaging and Distribution","description":"Ship your coding agent as a polished binary product, covering release builds, cross-compilation, package managers, auto-updates, and telemetry."},"headers":[],"relativePath":"learn/linear/17-packaging-and-distribution/index.md","filePath":"learn/linear/17-packaging-and-distribution/index.md"}'),r={name:"learn/linear/17-packaging-and-distribution/index.md"};function o(s,i,l,d,c,u){return a(),t("div",null,[...i[0]||(i[0]=[n('<h1 id="packaging-and-distribution" tabindex="-1">Packaging and Distribution <a class="header-anchor" href="#packaging-and-distribution" aria-label="Permalink to &quot;Packaging and Distribution&quot;">​</a></h1><p>You have built a coding agent that works on your machine. Now it needs to work on everyone else&#39;s machine too. This chapter covers the entire journey from development build to production distribution: optimizing release builds, cross-compiling for multiple platforms, static linking for dependency-free binaries, and packaging for distribution through Homebrew, cargo install, and GitHub releases.</p><p>We also tackle the ongoing concerns that arise after the initial release. Configuration file management ensures users can customize the agent without conflicts across updates. Auto-update mechanisms keep users on the latest version without manual intervention. Telemetry -- done respectfully -- gives you the data you need to improve the product while respecting user privacy.</p><p>Each topic addresses the specific challenges of distributing a Rust binary that depends on system libraries (OpenSSL, libgit2), needs to work across macOS, Linux, and Windows, and must handle graceful upgrades without disrupting active sessions. By the end, you will have a complete release pipeline that produces professional, installable binaries for all major platforms.</p><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>If you have ever tried to distribute a Python CLI tool, you know the pain: creating wheels, dealing with <code>manylinux</code> compatibility, bundling native extensions, writing <code>setup.py</code> or <code>pyproject.toml</code>, uploading to PyPI, hoping the user has the right Python version, creating virtual environments, and praying that <code>pip install</code> doesn&#39;t hit a C extension compilation error on the user&#39;s machine. Rust eliminates almost all of this. You compile once per platform and ship a single binary with zero runtime dependencies. No interpreter, no virtual environment, no dependency resolution at install time. This chapter is where Rust&#39;s practical advantage over Python becomes most dramatically clear.</p></div><h2 id="learning-objectives" tabindex="-1">Learning Objectives <a class="header-anchor" href="#learning-objectives" aria-label="Permalink to &quot;Learning Objectives&quot;">​</a></h2><ul><li>Configure Cargo for optimized release builds with appropriate LTO, codegen, and stripping settings</li><li>Cross-compile Rust binaries for macOS (Intel and Apple Silicon), Linux (glibc and musl), and Windows</li><li>Set up static linking to produce self-contained binaries without runtime dependencies</li><li>Package and distribute through Homebrew taps, cargo install, and GitHub binary releases</li><li>Implement platform-aware configuration file management using XDG conventions and OS-specific paths</li><li>Implement an auto-update system that checks for and applies updates without disrupting the user</li><li>Design privacy-respecting telemetry that provides actionable product insights</li></ul><h2 id="subchapters" tabindex="-1">Subchapters <a class="header-anchor" href="#subchapters" aria-label="Permalink to &quot;Subchapters&quot;">​</a></h2><ol><li><a href="/linear/17-packaging-and-distribution/01-release-builds.html">Release Builds</a></li><li><a href="/linear/17-packaging-and-distribution/02-cross-compilation.html">Cross Compilation</a></li><li><a href="/linear/17-packaging-and-distribution/03-static-linking.html">Static Linking</a></li><li><a href="/linear/17-packaging-and-distribution/04-cargo-install.html">Cargo Install</a></li><li><a href="/linear/17-packaging-and-distribution/05-homebrew-distribution.html">Homebrew Distribution</a></li><li><a href="/linear/17-packaging-and-distribution/06-binary-releases.html">Binary Releases</a></li><li><a href="/linear/17-packaging-and-distribution/07-config-file-management.html">Config File Management</a></li><li><a href="/linear/17-packaging-and-distribution/08-auto-updates.html">Auto Updates</a></li><li><a href="/linear/17-packaging-and-distribution/09-telemetry-considerations.html">Telemetry Considerations</a></li><li><a href="/linear/17-packaging-and-distribution/10-summary.html">Summary</a></li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Chapter 2 (Rust fundamentals and Cargo basics)</li><li>Familiarity with Cargo workspace configuration and build profiles</li><li>A working coding agent binary from previous chapters</li></ul>',11)])])}const g=e(r,[["render",o]]);export{h as __pageData,g as default};
